return items.map(item => {

  const pair =
    item.json.pairs?.[0];

  // ❌ Invalid pair
  if (!pair) {
    return { json: {} };
  }

  // 📊 Market metrics
  const volume =
    pair.volume?.h24 || 0;

  const liquidity =
    pair.liquidity?.usd || 1;

  const buys =
    pair.txns?.h24?.buys || 0;

  const sells =
    pair.txns?.h24?.sells || 0;

  const ratio =
    volume / liquidity;

  // ❌ Ignore weak activity
  if (volume < 5000) {
    return { json: {} };
  }

  // ❌ Ignore dead participation
  if (ratio < 0.1) {
    return { json: {} };
  }

  // ❌ Ignore suspicious wash activity
  if (ratio > 20) {
    return { json: {} };
  }

  // 📊 Confidence scoring
  let score = 0;

  if (volume > 100000)
    score += 2;

  if (liquidity > 80000)
    score += 2;

  if (buys > sells)
    score += 2;

  if (ratio > 0.8 && ratio < 8)
    score += 2;

  let confidence =
    "Low";

  if (score >= 7) {

    confidence =
      "High";
  }

  else if (score >= 5) {

    confidence =
      "Moderate";
  }

  // 🧠 Flow Classification
  let flow_type =
    "Neutral Flow";

  // 📈 Accumulation
  if (
    buys > sells * 1.2
  ) {

    flow_type =
      "Accumulation Activity";
  }

  // 📉 Distribution
  else if (
    sells > buys * 1.2
  ) {

    flow_type =
      "Distribution Activity";
  }

  // ✅ Final output
  return {

    json: {

      token:
        pair.baseToken?.symbol,

      chain:
        pair.chainId,

      volume,

      liquidity,

      buys,

      sells,

      ratio:
        ratio.toFixed(2),

      confidence,

      flow_type,

      score
    }
  };

}).filter(
  i =>
    i.json.token &&
    i.json.volume > 5000
);

