const users =
  items.map(i => i.json);

const signal =
  $('Smart Money Detector')
    .first()
    .json;

return users.map(user => {

  return {

    json: {

      ...signal,

      telegram_id:
        user.telegram_id
    }
  };

});

return items.map(item => {

  const d = item.json;

  // 🧠 Dynamic context
  let context =
    "Transactional activity remains balanced relative to current liquidity conditions.";

  if (
    d.flow_type ===
    "Accumulation Activity"
  ) {

    context =
      "Participation activity currently reflects constructive accumulation behavior.";
  }

  else if (
    d.flow_type ===
    "Distribution Activity"
  ) {

    context =
      "Defensive transactional activity is becoming increasingly observable.";
  }

  // 📨 Final message
  const message =
`Market Flow Analyzer

${d.token} — ${d.chain}

Flow Classification
${d.flow_type}

Participation Bias
${d.confidence}

Flow Metrics
• Volume Activity: ${Math.round(d.volume).toLocaleString()}
• Liquidity Base: ${Math.round(d.liquidity).toLocaleString()}
• Participation Ratio: ${d.ratio}

Market Context
${context}

System Note
This report is generated through automated liquidity-flow analysis for informational and analytical purposes only.`;

  return {

    json: {

      ...d,

      message
    }
  };

});
